1483:
SELECT SUM(Consumption) AS TotalConsumption
FROM yearmonth
WHERE CustomerID = 6 AND Date BETWEEN '201308' AND '201311';

1399:
SELECT CASE WHEN COUNT(*) > 0 THEN 'Yes' ELSE 'No' END AS attended
FROM member AS m
JOIN attendance AS a ON m.member_id = a.link_to_member
WHERE m.first_name = 'Maya' AND m.last_name = 'Mclean' AND a.link_to_event IN (
    SELECT event_id FROM event WHERE event_name = 'Women''s Soccer'
);

1148:
SELECT CAST(SUM(CASE WHEN T1.height < 180 AND T2.overall_rating > 70 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(T1.id) AS percentage
FROM Player AS T1
INNER JOIN Player_Attributes AS T2 ON T1.player_api_id = T2.player_api_id;

801:
SELECT CAST(SUM(CASE WHEN T2.gender = 'Male' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN T2.gender = 'Female' THEN 1 ELSE 0 END) AS ratio
FROM superhero AS T1
JOIN gender AS T2 ON T1.gender_id = T2.id;

829:
SELECT (SUM(CASE WHEN T2.publisher_name = 'DC Comics' THEN 1 ELSE 0 END) - SUM(CASE WHEN T2.publisher_name = 'Marvel Comics' THEN 1 ELSE 0 END)) AS difference
FROM superhero AS T1
JOIN publisher AS T2 ON T1.publisher_id = T2.id;

