SELECT EXISTS (
    SELECT 1
    FROM cards c
    JOIN foreign_data fd ON c.uuid = fd.uuid
    WHERE c.name = 'Ancestor''s Chosen' AND fd.language = 'Korean'
);

226:
SELECT CAST(SUM(CASE WHEN bond_type = '=' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS "percent"
FROM bond
WHERE molecule_id = 'TR008';
